select user_id,identifier,user_name,email,role,status,avatar,gender,birthday,signature,
       created_at,updated_at
from user


       (user_name like concat('%',#{query},'%')
        or identifier like concat('%',#{query},'%'))


        and user_id = #{userId}


        and status = #{status}


        and DATE(updated_at) between #{begin} and #{end}


     order by updated_at desc

